type IconType = 'md' | 'skill' | 'sh' | 'book'

function FileIcon({ type, active }: { type: IconType; active?: boolean }) {
  switch (type) {
    case 'md': return <IconMd active={active} />
    case 'skill': return <IconSkill active={active} />
    case 'sh': return <IconSh active={active} />
    case 'book': return <IconBook active={active} />
  }
}

