function inlineFormat(text: string, baseKey = 0): React.ReactNode {
  const segments: React.ReactNode[] = []
  let remaining = text
  let k = baseKey

  while (remaining.length > 0) {
    const codeIdx = remaining.indexOf('`')
    const boldIdx = remaining.indexOf('**')
    const italicIdx = (() => {
      let idx = remaining.indexOf('*')
      while (idx !== -1 && remaining[idx + 1] === '*') idx = remaining.indexOf('*', idx + 2)
      return idx
    })()

    const candidates = [
      codeIdx >= 0 ? codeIdx : Infinity,
      boldIdx >= 0 ? boldIdx : Infinity,
      italicIdx >= 0 ? italicIdx : Infinity,
    ]
    const minIdx = Math.min(...candidates)

    if (minIdx === Infinity) { segments.push(remaining); break }

    if (minIdx > 0) { segments.push(remaining.slice(0, minIdx)); remaining = remaining.slice(minIdx) }

    if (candidates[1] === minIdx) {
      // **bold**
      const end = remaining.indexOf('**', 2)
      if (end === -1) { segments.push(remaining); break }
      segments.push(<strong key={k++} style={{ color: '#FAFAF7', fontWeight: 700 }}>{remaining.slice(2, end)}</strong>)
      remaining = remaining.slice(end + 2)
    } else if (candidates[0] === minIdx) {
      // `code`
      const end = remaining.indexOf('`', 1)
      if (end === -1) { segments.push(remaining); break }
      segments.push(
        <code key={k++} style={{ fontFamily: 'var(--font-dm-mono), DM Mono, monospace', background: 'rgba(255,255,255,0.08)', padding: '1px 6px', borderRadius: 3, fontSize: '0.88em', color: '#E6C07B' }}>
          {remaining.slice(1, end)}
        </code>
      )
      remaining = remaining.slice(end + 1)
    } else {
      // *italic*
      const end = remaining.indexOf('*', 1)
      if (end === -1) { segments.push(remaining); break }
      segments.push(<em key={k++} style={{ color: '#BDBDB3', fontStyle: 'italic' }}>{remaining.slice(1, end)}</em>)
      remaining = remaining.slice(end + 1)
    }
  }

  return segments.length === 1 ? segments[0] : <>{segments}</>
}

function MarkdownPreview({ content }: { content: string }) {
  const lines = content.split('\n')
  return (
    <div style={{ padding: '20px 24px', fontFamily: 'var(--font-dm-sans), DM Sans, sans-serif', maxWidth: 680 }}>
      {lines.map((line, i) => {
        const t = line.trim()
        if (!t) return <div key={i} style={{ height: 8 }} />

        // ATX headings
        if (t.startsWith('# ')) return (
          <h1 key={i} style={{ color: '#E05C15', fontSize: 19, fontFamily: 'var(--font-syne), Syne, sans-serif', fontWeight: 800, margin: i > 0 ? '22px 0 6px' : '0 0 6px', lineHeight: 1.3 }}>
            {inlineFormat(t.slice(2), i * 100)}
          </h1>
        )
        if (t.startsWith('## ')) return (
          <h2 key={i} style={{ color: '#FAFAF7', fontSize: 14.5, fontFamily: 'var(--font-syne), Syne, sans-serif', fontWeight: 700, margin: '18px 0 5px', letterSpacing: 0.2 }}>
            {inlineFormat(t.slice(3), i * 100)}
          </h2>
        )
        if (t.startsWith('### ')) return (
          <h3 key={i} style={{ color: '#BDBDB3', fontSize: 13, fontFamily: 'var(--font-syne), Syne, sans-serif', fontWeight: 700, margin: '14px 0 4px' }}>
            {inlineFormat(t.slice(4), i * 100)}
          </h3>
        )
        if (t.startsWith('#### ')) return (
          <h4 key={i} style={{ color: '#AEACA5', fontSize: 12.5, fontFamily: 'var(--font-syne), Syne, sans-serif', fontWeight: 700, margin: '12px 0 3px' }}>
            {inlineFormat(t.slice(5), i * 100)}
          </h4>
        )

        // Bold-as-heading: entire line is **text** (model style)
        const boldHeading = t.match(/^\*\*(.+)\*\*$/)
        if (boldHeading) {
          const numSection = boldHeading[1].match(/^(\d+)\.\s+(.+)/)
          if (numSection) return (
            <h3 key={i} style={{ color: '#E05C15', fontSize: 13.5, fontFamily: 'var(--font-syne), Syne, sans-serif', fontWeight: 700, margin: '20px 0 5px', display: 'flex', gap: 8, alignItems: 'baseline' }}>
              <span style={{ fontSize: 10.5, opacity: 0.6, fontFamily: 'var(--font-dm-mono), DM Mono, monospace', flexShrink: 0 }}>{numSection[1]}.</span>
              {inlineFormat(numSection[2], i * 100)}
            </h3>
          )
          return (
            <h2 key={i} style={{ color: '#FAFAF7', fontSize: 14.5, fontFamily: 'var(--font-syne), Syne, sans-serif', fontWeight: 700, margin: '18px 0 5px', letterSpacing: 0.2 }}>
              {boldHeading[1]}
            </h2>
          )
        }

        // Italic subtitle: entire line is *text*
        const italicLine = t.match(/^\*([^*].+[^*])\*$/)
        if (italicLine) return (
          <p key={i} style={{ fontSize: 13, color: '#888', fontStyle: 'italic', margin: '0 0 12px', lineHeight: 1.6 }}>
            {italicLine[1]}
          </p>
        )

        // Horizontal rule
        if (/^(-{3,}|\*{3,}|_{3,})$/.test(t)) return (
          <hr key={i} style={{ border: 'none', borderTop: '1px solid #2A2A24', margin: '16px 0' }} />
        )

        // Ordered list: 1. or 1)
        const orderedMatch = t.match(/^(\d+)[.)]\s+(.+)/)
        if (orderedMatch) return (
          <div key={i} style={{ display: 'flex', gap: 10, marginBottom: 4, fontSize: 13.5, lineHeight: 1.65 }}>
            <span style={{ color: '#E05C15', opacity: 0.65, flexShrink: 0, fontFamily: 'var(--font-dm-mono), DM Mono, monospace', fontSize: 11, paddingTop: 3, minWidth: 16, textAlign: 'right' }}>{orderedMatch[1]}.</span>
            <span style={{ color: '#C8C6BC' }}>{inlineFormat(orderedMatch[2], i * 100)}</span>
          </div>
        )

        // Markdown bullets: - item or * item (with space)
        if (t.startsWith('- ') || t.startsWith('* ')) return (
          <div key={i} style={{ display: 'flex', gap: 10, marginBottom: 4, fontSize: 13.5, lineHeight: 1.65 }}>
            <span style={{ color: '#A8D8A4', flexShrink: 0, marginTop: 2 }}>•</span>
            <span style={{ color: '#C8C6BC' }}>{inlineFormat(t.slice(2), i * 100)}</span>
          </div>
        )

        // Direct bullet character: • item
        if (t.startsWith('•')) return (
          <div key={i} style={{ display: 'flex', gap: 10, marginBottom: 4, fontSize: 13.5, lineHeight: 1.65 }}>
            <span style={{ color: '#A8D8A4', flexShrink: 0, marginTop: 2 }}>•</span>
            <span style={{ color: '#C8C6BC' }}>{inlineFormat(t.slice(1).trim(), i * 100)}</span>
          </div>
        )

        // Arrow lines
        if (t.startsWith('→') || t.startsWith('->')) return (
          <div key={i} style={{ display: 'flex', gap: 8, marginBottom: 4, fontSize: 13, fontFamily: 'var(--font-dm-mono), DM Mono, monospace', color: '#7AB8F5' }}>
            {t}
          </div>
        )

        // Blockquote
        if (t.startsWith('> ')) return (
          <div key={i} style={{ borderLeft: '2px solid #E05C15', paddingLeft: 12, marginBottom: 6, fontSize: 13.5, color: '#888', fontStyle: 'italic', lineHeight: 1.65 }}>
            {inlineFormat(t.slice(2), i * 100)}
          </div>
        )

        // Table row: | cell | cell |
        if (t.startsWith('|') && t.endsWith('|')) {
          if (/^\|[\s\-:|]+\|$/.test(t)) return <div key={i} />
          const cells = t.slice(1, -1).split('|').map(c => c.trim())
          return (
            <div key={i} style={{ display: 'flex', marginBottom: 1 }}>
              {cells.map((cell, ci) => (
                <div key={ci} style={{ flex: 1, padding: '4px 8px', borderBottom: '1px solid #2A2A24', fontSize: 12.5, color: '#C8C6BC' }}>
                  {inlineFormat(cell, i * 100 + ci)}
                </div>
              ))}
            </div>
          )
        }

        // Source citation
        if (t.startsWith('[Source')) return (
          <div key={i} style={{ fontSize: 11, color: '#555', fontFamily: 'var(--font-dm-mono), DM Mono, monospace', marginTop: 4, marginBottom: 8 }}>
            {t}
          </div>
        )

        // Default paragraph with inline formatting
        return (
          <p key={i} style={{ fontSize: 13.5, color: '#C8C6BC', margin: '0 0 3px', lineHeight: 1.75 }}>
            {inlineFormat(t, i * 100)}
          </p>
        )
      })}
    </div>
  )
}

async function generateShareCaption(claudeMd: string, skills: ForgeResult['skills'], tags: string[]): Promise<string> {
  const res = await fetch('/api/test-drive', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      messages: [
        { role: 'system', content: 'You are a developer tweet writer. Generate a single engaging tweet (under 220 characters) for a developer who just had Ferra (claudemdforge.site) generate a custom CLAUDE.md setup. Mention the stack/skills if interesting. Include #ClaudeCode at the end. Output ONLY the tweet text - no quotes, no preamble.' },
        { role: 'user', content: `Stack: ${tags.join(', ')}\nSkills: ${skills.map(s => s.title).join(', ')}\n\nCLAUDE.md preview:\n${claudeMd.slice(0, 500)}` },
      ],
    }),
  })
  const data = await res.json()
  return (data.content as string) ?? `Just had Ferra forge my perfect CLAUDE.md with ${skills.length} skills for ${tags.slice(0, 2).join(' + ')} - claudemdforge.site #ClaudeCode`
}

type FileEntry = { id: string; icon: IconType; label: string; lang?: string; content: string }

export default function ResultPreview({ result }: Props) {
  const [activeId, setActiveId] = useState('claude-md')
  const [viewMode, setViewMode] = useState<'code' | 'preview'>('code')
  const [copied, setCopied] = useState(false)
  const [sharing, setSharing] = useState(false)
  const [skillsOpen, setSkillsOpen] = useState(false)

  const files: FileEntry[] = [
    { id: 'claude-md', icon: 'md', label: 'CLAUDE.md', lang: 'markdown', content: result.claudeMd },
    ...result.skills.map(s => ({
      id: `skill-${s.id}`,
      icon: 'skill' as IconType,
      label: toSlug(s.title),
      lang: 'markdown',
      content: s.snippet,
    })),
    { id: 'hook', icon: 'sh', label: 'pre-commit.sh', lang: 'bash', content: PRE_COMMIT_SH },
    { id: 'setup', icon: 'book', label: 'SETUP_GUIDE.md', lang: 'markdown', content: SETUP_GUIDE },
  ]

  const active = files.find(f => f.id === activeId) ?? files[0]

  function downloadZip() {
    const url = URL.createObjectURL(result.zipBlob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'claude-forge-output.zip'
    a.click()
    URL.revokeObjectURL(url)
  }

  async function copyActive() {
    await navigator.clipboard.writeText(active.content)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  async function shareOnX() {
    setSharing(true)
    try {
      const caption = await generateShareCaption(result.claudeMd, result.skills, result.tags)
      window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(caption + '\n\nclaudemdforge.site')}`, '_blank', 'noopener,noreferrer')
    } catch {
      const fallback = `Just had Ferra forge my CLAUDE.md with ${result.skills.length} skills - claudemdforge.site #ClaudeCode`
      window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(fallback)}`, '_blank', 'noopener,noreferrer')
    } finally {
      setSharing(false)
    }
  }

  return (
    <div style={{ marginTop: 48 }}>

      {/* Success banner */}
      <div style={{
        display: 'flex', alignItems: 'center',
        padding: '14px 20px', marginBottom: 2,
        background: 'linear-gradient(135deg, #F0FDF4 0%, #ECFDF5 100%)',
        border: '1px solid #BBF7D0', borderRadius: '14px 14px 0 0',
        flexWrap: 'wrap', gap: 10,
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#22C55E', boxShadow: '0 0 0 3px rgba(34,197,94,0.2)' }} />
          <span style={{ fontFamily: 'var(--font-syne), Syne, sans-serif', fontWeight: 700, fontSize: 13.5, color: '#15803D' }}>
            Forge complete
          </span>
        </div>
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'center' }}>
          <span className="mono" style={{ fontSize: 11, padding: '3px 9px', borderRadius: 5, background: '#DCFCE7', border: '1px solid #86EFAC', color: '#15803D' }}>
            {files.length} files
          </span>
          <button
            className="mono"
            onClick={() => setSkillsOpen(true)}
            style={{
              fontSize: 11, padding: '3px 9px', borderRadius: 5,
              background: '#EFF6FF', border: '1px solid #93C5FD', color: '#1D4ED8',
              cursor: 'pointer', transition: 'all 0.15s', display: 'inline-flex', alignItems: 'center', gap: 4,
            }}
            onMouseOver={e => { (e.currentTarget).style.background = '#DBEAFE'; (e.currentTarget).style.borderColor = '#60A5FA' }}
            onMouseOut={e => { (e.currentTarget).style.background = '#EFF6FF'; (e.currentTarget).style.borderColor = '#93C5FD' }}
          >
            {result.skills.length} skills
            <svg viewBox="0 0 24 24" width="10" height="10" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="6 9 12 15 18 9" />
            </svg>
          </button>
          {result.tags.slice(0, 3).map(t => (
            <span key={t} className="mono" style={{ fontSize: 11, padding: '3px 9px', borderRadius: 5, background: 'var(--orange-light)', border: '1px solid var(--orange-border)', color: 'var(--orange)' }}>{t}</span>
          ))}
        </div>
        <div style={{ flex: 1 }} />
        <div style={{ display: 'flex', gap: 8 }}>
          <button className="btn-dark" onClick={copyActive} style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}>
            {copied ? (
              <>
                <svg viewBox="0 0 24 24" width="13" height="13" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12" /></svg>
                Copied
              </>
            ) : (
              <>
                <CopyIcon />
                Copy {active.label}
              </>
            )}
          </button>
          <button className="btn-primary" style={{ fontSize: 13, padding: '9px 18px' }} onClick={downloadZip}>
            &#8595; Download ZIP
          </button>
        </div>
      </div>

      {/* IDE layout */}
      <div style={{
        display: 'grid', gridTemplateColumns: '220px 1fr',
        border: '1px solid #2A2A24', borderTop: 'none',
        borderRadius: '0 0 14px 14px', overflow: 'hidden',
        background: '#141410',
        minHeight: 440,
      }}>
        {/* File tree sidebar */}
        <div style={{ borderRight: '1px solid #2A2A24', background: '#1A1A15' }}>
          {[
            { label: 'claude-forge-output/', items: files.filter(f => f.id === 'claude-md') },
            { label: 'skills/', items: files.filter(f => f.id.startsWith('skill-')) },
            { label: 'hooks/', items: files.filter(f => f.id === 'hook') },
            { label: '', items: files.filter(f => f.id === 'setup') },
          ].map(group => (
            <div key={group.label}>
              {group.label && (
                <div style={{
                  padding: '7px 14px 4px',
                  fontSize: 10.5,
                  fontFamily: 'var(--font-dm-mono), DM Mono, monospace',
                  color: 'var(--faint)',
                  letterSpacing: 0.5,
                  userSelect: 'none',
                }}>
                  {group.label}
                </div>
              )}
              {group.items.map(f => (
                <button
                  key={f.id}
                  onClick={() => setActiveId(f.id)}
                  style={{
                    width: '100%', textAlign: 'left',
                    padding: '7px 14px 7px 22px',
                    display: 'flex', alignItems: 'center', gap: 7,
                    background: activeId === f.id ? '#252520' : 'transparent',
                    borderTop: 'none', borderRight: 'none', borderBottom: 'none',
                    borderLeft: activeId === f.id ? '2px solid var(--orange)' : '2px solid transparent',
                    cursor: 'pointer', transition: 'background 0.12s',
                    fontFamily: 'var(--font-dm-mono), DM Mono, monospace',
                    fontSize: 12, color: activeId === f.id ? '#FAFAF7' : '#666',
                    whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
                  }}
                >
                  <FileIcon type={f.icon} active={activeId === f.id} />
                  <span style={{ overflow: 'hidden', textOverflow: 'ellipsis' }}>{f.label}</span>
                </button>
              ))}
            </div>
          ))}
        </div>

        {/* Content pane */}
        <div style={{ display: 'flex', flexDirection: 'column', minWidth: 0 }}>
          {/* Tab bar */}
          <div style={{
            display: 'flex', alignItems: 'center',
            borderBottom: '1px solid #2A2A24', background: '#1A1A15',
            padding: '0 16px', height: 36, flexShrink: 0, gap: 8,
          }}>
            <span style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 12, fontFamily: 'var(--font-dm-mono), DM Mono, monospace', color: '#888', flexShrink: 0 }}>
              <FileIcon type={active.icon} /> {active.label}
            </span>

            {active.id === 'claude-md' && (
              <div style={{ display: 'flex', gap: 2, marginLeft: 10, background: '#252520', borderRadius: 6, padding: 2 }}>
                <button
                  onClick={() => setViewMode('code')}
                  style={{
                    fontSize: 10.5, padding: '3px 10px', borderRadius: 4, cursor: 'pointer',
                    background: viewMode === 'code' ? '#3A3A32' : 'transparent',
                    color: viewMode === 'code' ? '#FAFAF7' : '#555',
                    border: 'none', fontFamily: 'var(--font-dm-mono), DM Mono, monospace',
                    transition: 'all 0.12s',
                  }}
                >Code</button>
                <button
                  onClick={() => setViewMode('preview')}
                  style={{
                    fontSize: 10.5, padding: '3px 10px', borderRadius: 4, cursor: 'pointer',
                    background: viewMode === 'preview' ? '#3A3A32' : 'transparent',
                    color: viewMode === 'preview' ? '#FAFAF7' : '#555',
                    border: 'none', fontFamily: 'var(--font-dm-mono), DM Mono, monospace',
                    transition: 'all 0.12s',
                  }}
                >Preview</button>
              </div>
            )}

            {active.lang && (
              <span className="mono" style={{ marginLeft: 'auto', fontSize: 10, color: '#555', background: '#252520', padding: '2px 7px', borderRadius: 4 }}>
                {active.lang}
              </span>
            )}
          </div>

          {/* Code / Preview area */}
          <div style={{ flex: 1, overflow: 'auto', background: '#141410' }}>
            {active.id === 'claude-md' && viewMode === 'preview' ? (
              <MarkdownPreview content={result.claudeMd} />
            ) : active.id === 'claude-md' ? (
              <div style={{ padding: '18px 22px', fontFamily: 'var(--font-dm-mono), DM Mono, monospace', fontSize: 12.5, lineHeight: 1.85, whiteSpace: 'pre-wrap' }}>
                {result.claudeMd.split('\n').map((line, i) => (
                  <div key={i} style={{ color: colorLine(line) }}>{line || ' '}</div>
                ))}
              </div>
            ) : (
              <pre style={{
                padding: '18px 22px',
                fontFamily: 'var(--font-dm-mono), DM Mono, monospace',
                fontSize: 12.5, lineHeight: 1.85, margin: 0,
                color: '#D4D2C9', whiteSpace: 'pre-wrap', wordBreak: 'break-word',
              }}>
                {active.content}
              </pre>
            )}
          </div>

          {/* Status bar */}
          <div style={{
            borderTop: '1px solid #2A2A24', background: '#0F0F0C',
            padding: '5px 16px', display: 'flex', alignItems: 'center', gap: 16, flexShrink: 0,
          }}>
            <span className="mono" style={{ fontSize: 10.5, color: '#444' }}>
              {active.content.split('\n').length} lines
            </span>
            <span className="mono" style={{ fontSize: 10.5, color: '#444' }}>
              {(active.content.length / 1024).toFixed(1)} kb
            </span>
            <div style={{ flex: 1 }} />
            <span className="mono" style={{ fontSize: 10.5, color: '#444' }}>
              UTF-8 &middot; {active.lang ?? 'plaintext'}
            </span>
          </div>
        </div>
      </div>

      {skillsOpen && <SkillsModal skills={result.skills} onClose={() => setSkillsOpen(false)} />}

      {/* Share strip */}
      <div className="share-box" style={{ marginTop: 16 }}>
        <svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor" style={{ flexShrink: 0 }}>
          <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-4.714-6.231-5.401 6.231H2.739l7.73-8.835L1.254 2.25H8.08l4.713 6.068zm-1.161 17.52h1.833L7.084 4.126H5.117z" />
        </svg>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 13.5, fontWeight: 600, marginBottom: 2 }}>Share your forge</div>
          <div style={{ fontSize: 12.5, color: '#888' }}>
            {sharing ? 'Ferra is writing your tweet...' : 'Ferra writes a custom caption from your CLAUDE.md - every share helps.'}
          </div>
        </div>
        <button
          className="btn-outline"
          style={{ fontSize: 13, padding: '9px 18px', whiteSpace: 'nowrap', opacity: sharing ? 0.6 : 1 }}
          onClick={shareOnX}
          disabled={sharing}
        >
          {sharing ? 'Generating...' : 'Share on X →'}
        </button>
      </div>
    </div>
  )
}
